<template><nav class="bottom-nav"><button v-for="item in items" :class="{active:route.path===item.path}" @click="navigate(item.path)"><span class="nav-icon"><component :is="item.icon"/><b v-if="item.path==='/messages'&&unread">{{unread>99?'99+':unread}}</b></span><small>{{item.label}}</small></button></nav></template>
<script setup lang="ts">import {onBeforeUnmount,onMounted,ref} from 'vue';import {House,MessageCircle,ClipboardList,Package,Wallet,Settings} from 'lucide-vue-next';import {navigate,route} from '../router';const unread=ref(0);const items:any[]=[['/','首页',House],['/messages','消息',MessageCircle],['/orders','订单',ClipboardList],['/products','商品',Package],['/finance','财务',Wallet],['/settings','设置',Settings]].map(([path,label,icon])=>({path,label,icon}));let timer:number|undefined;async function load(){try{const r=await fetch('/api/koshop-seller/messages/unread-count'),j=await r.json();if(r.ok)unread.value=Number(j.count)||0}catch{}}function stop(){if(timer!==undefined){clearInterval(timer);timer=undefined}}function start(){stop();if(!document.hidden)timer=window.setInterval(load,5000)}function visibility(){if(document.hidden)stop();else{load();start()}}onMounted(()=>{load();start();document.addEventListener('visibilitychange',visibility)});onBeforeUnmount(()=>{stop();document.removeEventListener('visibilitychange',visibility)})</script>
